using UnityEditor;
using UnityEngine;

public static class RegisterNetworkPrefabsEditor
{
    [MenuItem("Netcode/Prepare Pinguim Prefab (Add NetworkObject)")]
    public static void PreparePinguimPrefab()
    {
        var guids = AssetDatabase.FindAssets("Pinguim t:prefab");
        if (guids == null || guids.Length == 0)
        {
            Debug.LogError("Prefab 'Pinguim' não encontrado. Coloque-o em Assets/Prefabs ou nomeie como 'Pinguim'.");
            return;
        }

        string prefabPath = AssetDatabase.GUIDToAssetPath(guids[0]);
        var root = PrefabUtility.LoadPrefabContents(prefabPath);
        if (root == null)
        {
            Debug.LogError($"Falha ao abrir o prefab em '{prefabPath}'.");
            return;
        }

        var type = System.Type.GetType("Unity.Netcode.NetworkObject, Unity.Netcode.Runtime") ?? System.Type.GetType("Unity.Netcode.NetworkObject");
        if (type == null)
        {
            Debug.LogWarning("Tipo NetworkObject não encontrado. Instale o pacote Netcode for GameObjects antes de executar este utilitário.");
            PrefabUtility.UnloadPrefabContents(root);
            return;
        }

        if (root.GetComponent(type) == null)
        {
            root.AddComponent(type);
            PrefabUtility.SaveAsPrefabAsset(root, prefabPath);
            Debug.Log("Adicionado NetworkObject ao prefab Pinguim.");
        }
        else
        {
            Debug.Log("Prefab Pinguim já possui NetworkObject.");
        }

        PrefabUtility.UnloadPrefabContents(root);
        Debug.Log($"Preparação concluída para prefab: {prefabPath}. Registre-o no NetworkManager (Inspector) se necessário.");
    }

    [MenuItem("Netcode/Create NetworkManager GameObject in Scene")]
    public static void CreateNetworkManagerInScene()
    {
        // Verifica se já existe
        var existing = Object.FindObjectOfType(typeof(Unity.Netcode.NetworkManager));
        if (existing != null)
        {
            Debug.Log("Já existe um NetworkManager na cena.");
            return;
        }

        GameObject go = new GameObject("NetworkManager");

        var type = System.Type.GetType("Unity.Netcode.NetworkManager, Unity.Netcode.Runtime") ?? System.Type.GetType("Unity.Netcode.NetworkManager");
        if (type == null)
        {
            Debug.LogWarning("Tipo NetworkManager não encontrado. Instale o pacote Netcode for GameObjects antes de executar este utilitário.");
            return;
        }

        go.AddComponent(type);
        Selection.activeGameObject = go;
        Debug.Log("NetworkManager criado na cena. Configure o Transport (ex: Unity Transport) e registre os NetworkPrefabs via Inspector.");
    }
}

using UnityEngine;

namespace JogosEmRede
{
    public class BlocoDeGelo : MonoBehaviour
    {
        // Coordenadas do bloco na grade (preenchidas pelo Gerador)
        [HideInInspector] public int gridX;
        [HideInInspector] public int gridY;
        [HideInInspector] public bool protegido = false;

        [Header("Configurações de Rachadura")]
        // Arraste suas 4 imagens aqui no Inspector (Element 0, Element 1, Element 2, Element 3)
        public Sprite[] spritesRachadura; 

        private int batidasAtuais = 0;
        private SpriteRenderer spriteRenderer;

        void Awake()
        {
            // Pega o componente que desenha a imagem do bloco
            spriteRenderer = GetComponent<SpriteRenderer>();
        }

        void Start()
        {
            // Garante que o bloco começa com a primeira imagem (intacto) se houver sprites na lista
            if (spritesRachadura != null && spritesRachadura.Length > 0)
            {
                spriteRenderer.sprite = spritesRachadura[0];
            }
        }

        /// <summary>
        /// Aplica dano ao bloco. Se o bloco não estiver protegido, incrementa o contador de batidas,
        /// atualiza o sprite de rachadura e destrói o bloco se exceder o limite de imagens.
        /// </summary>
        /// <param name="dano">Quantidade de dano a aplicar (padrão: 1)</param>
        public void ReceberDano(int dano = 1)
        {
            // Se for o bloco central protegido, não faz nada
            if (protegido) return;

            // Avança para a próxima batida/rachadura
            batidasAtuais += dano;

            // CORREÇÃO: Se o dano foi 4, batidasAtuais vai direto para 4. 
            // Se spritesRachadura.Length for 4, precisamos quebrar o bloco imediatamente!
            if (batidasAtuais < spritesRachadura.Length)
            {
                spriteRenderer.sprite = spritesRachadura[batidasAtuais];
                Debug.Log($"[Bloco] Sofreu dano! Batidas: {batidasAtuais}/{spritesRachadura.Length}");
            }
            else
            {
                // Se o dano atingiu ou passou do limite de sprites, o bloco quebra!
                QuebrarBloco();
            }
        }

        // CORREÇÃO: Removeu-se o método OnMouseDown() antigo que causava conflitos de clique duplicado!

        private void QuebrarBloco()
        {
            Debug.Log($"[Bloco] Bloco em ({gridX}, {gridY}) foi totalmente destruído!");

            // Avisa o tabuleiro para remover este bloco da lógica e checar a estabilidade
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.ReportBlockDestroyed(gridX, gridY);
                // CORREÇÃO: Removeu-se o AlternarTurno() daqui de dentro! 
                // Quem cuida de passar o turno agora é APENAS o ControleDeClique.
            }

            // Remove o objeto do jogo
            Destroy(gameObject);

            // Em BlocoDeGelo.cs quando o bloco é destruído/interage:
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.ReportBlockDestroyed(gridX, gridY);
            }
        }
    }
}

using UnityEngine;
using Unity.Netcode;

namespace JogosEmRede
{
    public class BlocoDeGelo : MonoBehaviour
    {
        // Coordenadas do bloco na grade (preenchidas pelo Gerador)
        [HideInInspector] public int gridX;
        [HideInInspector] public int gridY;
        [HideInInspector] public bool protegido = false;

        [Header("Configurações de Rachadura")]
        // Arraste suas 4 imagens aqui no Inspector (Element 0, Element 1, Element 2, Element 3)
        public Sprite[] spritesRachadura; 

        private int batidasAtuais = 0;
        private SpriteRenderer spriteRenderer;

        void Awake()
        {
            // Pega o componente que desenha a imagem do bloco
            spriteRenderer = GetComponent<SpriteRenderer>();
        }

        void Start()
        {
            // Garante que o bloco começa com a primeira imagem (intacto) se houver sprites na lista
            if (spritesRachadura != null && spritesRachadura.Length > 0)
            {
                spriteRenderer.sprite = spritesRachadura[0];
            }
        }

        /// <summary>
        /// Aplica dano ao bloco. Se o bloco não estiver protegido, incrementa o contador de batidas,
        /// atualiza o sprite de rachadura e destrói o bloco se exceder o limite de imagens.
        /// </summary>
        /// <param name="dano">Quantidade de dano a aplicar (padrão: 1)</param>
        public void ReceberDano(int dano = 1)
        {
            // Se for o bloco central protegido, não faz nada
            if (protegido) return;

            // Avança para a próxima batida/rachadura
            batidasAtuais += dano;

            // CORREÇÃO: Se o dano foi 4, batidasAtuais vai direto para 4. 
            // Se spritesRachadura.Length for 4, precisamos quebrar o bloco imediatamente!
            if (batidasAtuais < spritesRachadura.Length)
            {
                spriteRenderer.sprite = spritesRachadura[batidasAtuais];
                Debug.Log($"[Bloco] Sofreu dano! Batidas: {batidasAtuais}/{spritesRachadura.Length}");
            }
            else
            {
                // Se o dano atingiu ou passou do limite de sprites, o bloco quebra!
                QuebrarBloco();
            }
        }

        // CORREÇÃO: Removeu-se o método OnMouseDown() antigo que causava conflitos de clique duplicado!

        private void QuebrarBloco()
        {
            Debug.Log($"[Bloco] Bloco em ({gridX}, {gridY}) foi totalmente destruído!");

            // Solicita ao GeradorDeTabuleiro que registre a destruição (servidor faz a validação)
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.ReportBlockDestroyed(gridX, gridY);
                // Quem alterna o turno é o ControleDeClique; aqui apenas notificamos a remoção.
            }

            // Somente o servidor destrói fisicamente o GameObject localmente.
            if (NetworkManager.Singleton != null && NetworkManager.Singleton.IsServer)
            {
                Destroy(gameObject);
            }
            // Clientes aguardam a atualização via NetworkList (gridState) que removerá o visual.
        }
    }
}

using UnityEngine;

public class BoardManager : MonoBehaviour
{
    public static BoardManager Instance;

    public ChessPiece[,] chessPieces = new ChessPiece[8,8];


    [SerializeField]
    private GameObject whiteQueenPrefab;

    [SerializeField]
    private GameObject blackQueenPrefab;

    private void Awake()
    {

        Instance = this;
    }

    public bool IsInsideBoard(Vector2Int pos)
    {
        return pos.x >= 0 &&
               pos.x < 8 &&
               pos.y >= 0 &&
               pos.y < 8;
    }

    public ChessPiece GetPiece(Vector2Int pos)
    {
        return chessPieces[pos.x, pos.y];
    }

    public void MovePiece(
        ChessPiece piece,
        Vector2Int targetPos
    )
    {
        chessPieces[
            piece.boardPosition.x,
            piece.boardPosition.y
        ] = null;

        ChessPiece target =
            chessPieces[targetPos.x, targetPos.y];

        if (target != null)
        {
            Destroy(target.gameObject);
        }

        piece.Move(targetPos);

        chessPieces[
            targetPos.x,
            targetPos.y
        ] = piece;

        CheckPromotion(piece);

        TeamColor enemyTeam =
            piece.team == TeamColor.White
                ? TeamColor.Black
                : TeamColor.White;

        if (CheckForCheckmate(enemyTeam))
        {
            Debug.Log("XEQUE-MATE");
        }
        else if (IsKingInCheck(enemyTeam))
        {
            Debug.Log("XEQUE");
        }

        TurnManager.Instance.EndTurn();
    }
    public bool IsKingInCheck(TeamColor kingTeam)
    {
        ChessPiece king = null;

        foreach (ChessPiece piece in chessPieces)
        {
            if (piece != null &&
                piece.team == kingTeam &&
                piece is King)
            {
                king = piece;
                break;
            }
        }

        if (king == null)
            return false;

        foreach (ChessPiece piece in chessPieces)
        {
            if (piece != null &&
                piece.team != kingTeam)
            {
                List<Vector2Int> moves =
                    piece.GetAvailableMoves(
                        chessPieces,
                        8,
                        8
                    );

                if (moves.Contains(king.boardPosition))
                {
                    return true;
                }
            }
        }

        return false;
    }
    public bool SimulateMoveForSinglePiece(
        ChessPiece piece,
        Vector2Int targetPos
    )
    {
        Vector2Int originalPos =
            piece.boardPosition;

        ChessPiece targetPiece =
            chessPieces[targetPos.x, targetPos.y];

        chessPieces[
            originalPos.x,
            originalPos.y
        ] = null;

        piece.boardPosition = targetPos;

        chessPieces[
            targetPos.x,
            targetPos.y
        ] = piece;

        bool kingInCheck =
            IsKingInCheck(piece.team);

        piece.boardPosition = originalPos;

        chessPieces[
            originalPos.x,
            originalPos.y
        ] = piece;

        chessPieces[
            targetPos.x,
            targetPos.y
        ] = targetPiece;

        return !kingInCheck;
    }
    public bool CheckForCheckmate(TeamColor team)
    {
        if (!IsKingInCheck(team))
            return false;

        foreach (ChessPiece piece in chessPieces)
        {
            if (piece == null ||
                piece.team != team)
                continue;

            List<Vector2Int> moves =
                piece.GetAvailableMoves(
                    chessPieces,
                    8,
                    8
                );

            foreach (Vector2Int move in moves)
            {
                if (SimulateMoveForSinglePiece(
                        piece,
                        move))
                {
                    return false;
                }
            }
        }

        return true;
    }
    public void CheckPromotion(ChessPiece piece)
    {
        if (!(piece is Pawn))
            return;

        if (piece.team == TeamColor.White &&
            piece.boardPosition.y == 7)
        {
            PromotePawn(piece);
        }

        if (piece.team == TeamColor.Black &&
            piece.boardPosition.y == 0)
        {
            PromotePawn(piece);
        }
    }
    void PromotePawn(ChessPiece pawn)
    {
        Vector2Int pos =
            pawn.boardPosition;

        GameObject prefab =
            pawn.team == TeamColor.White
                ? whiteQueenPrefab
                : blackQueenPrefab;

        Destroy(pawn.gameObject);

        GameObject newQueen =
            Instantiate(
                prefab,
                new Vector3(pos.x, 0, pos.y),
                Quaternion.identity
            );

        ChessPiece queen =
            newQueen.GetComponent<ChessPiece>();

        queen.team = pawn.team;
        queen.boardPosition = pos;

        chessPieces[pos.x, pos.y] = queen;
    }
}

