using UnityEngine;
using System.Collections.Generic;

public class InputManager : MonoBehaviour
{
    private ChessPiece selectedPiece;

    private List<Vector2Int> availableMoves;

    void Update()
    {
        if(Input.GetMouseButtonDown(0))
        {
            Ray ray = Camera.main.ScreenPointToRay(
                Input.mousePosition
            );

            if(Physics.Raycast(ray, out RaycastHit hit))
            {
                Vector2Int clickedPos = new Vector2Int(
                    Mathf.RoundToInt(hit.point.x),
                    Mathf.RoundToInt(hit.point.z)
                );

                HandleClick(clickedPos);
            }
        }
    }

    void HandleClick(Vector2Int pos)
    {
        ChessPiece piece =
            BoardManager.Instance.GetPiece(pos);

        // Selecionar peça
        if(selectedPiece == null)
        {
            if(piece != null &&
               TurnManager.Instance.IsPlayerTurn(piece.team))
            {
                selectedPiece = piece;

                availableMoves =
                    piece.GetAvailableMoves(
                        BoardManager.Instance.chessPieces,
                        8,
                        8
                    );

                Debug.Log("Peça selecionada");
            }
        }
        else
        {
            // Mover
            if(availableMoves.Contains(pos))
            {
                BoardManager.Instance.MovePiece(
                    selectedPiece,
                    pos
                );
            }

            selectedPiece = null;
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

public class InputManager : MonoBehaviour
{
    private ChessPiece selectedPiece;

    private List<Vector2Int> availableMoves;

    void Update()
    {
        if(Input.GetMouseButtonDown(0))
        {
            Ray ray = Camera.main.ScreenPointToRay(
                Input.mousePosition
            );

            if(Physics.Raycast(ray, out RaycastHit hit))
            {
                Vector2Int clickedPos = new Vector2Int(
                    Mathf.RoundToInt(hit.point.x),
                    Mathf.RoundToInt(hit.point.z)
                );

                HandleClick(clickedPos);
            }
        }
    }

    void HandleClick(Vector2Int pos)
    {
        ChessPiece piece =
            BoardManager.Instance.GetPiece(pos);

        // Selecionar peça
        if(selectedPiece == null)
        {
            if(piece != null &&
               piece.team == TurnManager.Instance.currentTurn)
            {
                selectedPiece = piece;

                availableMoves =
                    piece.GetAvailableMoves(
                        BoardManager.Instance.chessPieces,
                        8,
                        8
                    );

                Debug.Log("Peça selecionada");
            }
        }
        else
        {
            // Mover
            if(availableMoves.Contains(pos))
            {
                BoardManager.Instance.MovePiece(
                    selectedPiece,
                    pos
                );
            }

            selectedPiece = null;
        }
    }
}

using UnityEngine;
using TMPro; // Necessário para usar o TextMeshPro
using UnityEngine.SceneManagement; // OBRIGATÓRIO para conseguir reiniciar a cena

namespace JogosEmRede
{
    public class ControladorDeUI : MonoBehaviour
    {
        [Header("Configurações do Turno")]
        public TextMeshProUGUI textoTurno; // Arraste seu texto de turno aqui

        [Header("Configurações de Fim de Jogo")]
        public GameObject painelFimDeJogo; // Arraste o Painel/Pop-up de Game Over aqui
        public TextMeshProUGUI textoResultado; // Arraste o texto que diz quem ganhou aqui

        void Start()
        {
            // Garante que a tela de Game Over comece escondida ao iniciar o jogo
            if (painelFimDeJogo != null)
            {
                painelFimDeJogo.SetActive(false);
            }

            // Se inscreve nos eventos do tabuleiro para atualizar a tela automaticamente
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.OnTurnoAlterado += AtualizarTextoTurno;
                GeradorDeTabuleiro.Instance.OnGameOver += MostrarTelaDeVitoria;

                // AJUSTE INICIAL: Sorteia a força do primeiro turno assim que o jogo começa
                GeradorDeTabuleiro.Instance.forcaDoTurnoAtual = Random.Range(1, 5);
                // Força a UI a mostrar os dados certos do Jogador 1 logo no início
                AtualizarTextoTurno(GeradorDeTabuleiro.Instance.turnoAtual);
            }
        }

        void OnDestroy()
        {
            // Limpa as inscrições de eventos para evitar erros de memória
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.OnTurnoAlterado -= AtualizarTextoTurno;
                GeradorDeTabuleiro.Instance.OnGameOver -= MostrarTelaDeVitoria;
            }
        }

        // --- MODIFICAÇÃO AQUI: Mostra o turno E a força sorteada ---
        private void AtualizarTextoTurno(int turno)
        {
            if (textoTurno != null && GeradorDeTabuleiro.Instance != null)
            {
                int forca = GeradorDeTabuleiro.Instance.forcaDoTurnoAtual;

                // \n pula para a linha de baixo para o texto não ficar gigante pro lado
                textoTurno.text = $"Vez do Jogador {turno}\nForça do Golpe: {forca}";
            }
        }

        /// <summary>
        /// Ativa a tela de fim de jogo e anuncia o grande vencedor!
        /// </summary>
        private void MostrarTelaDeVitoria(int jogadorVencedor)
        {
            if (painelFimDeJogo != null)
            {
                painelFimDeJogo.SetActive(true); // Acende a tela com o botão de reiniciar
            }

            if (textoResultado != null)
            {
                textoResultado.text = $"       O Pinguim caiu!\n JOGADOR {jogadorVencedor} VENCEU! ";
            }
        }

        /// <summary>
        /// FUNÇÃO PÚBLICA DO BOTÃO: Recarrega a partida do zero.
        /// Ela vai aparecer no seu menu 'No Function' agora por causa do 'public void'.
        /// </summary>
        public void ReiniciarPartida()
        {
            Debug.Log("[UI] O botão foi clicado! Reiniciando o tabuleiro...");

            // Certifique-se de que o nome da sua cena na Unity seja exatamente "QuebraGelo"
            SceneManager.LoadScene("QuebraGelo");
        }
    }
}

using UnityEngine;
using TMPro;
using UnityEngine.SceneManagement;
using Unity.Netcode;

namespace JogosEmRede
{
    public class ControladorDeUI : MonoBehaviour
    {
        [Header("Configurações do Turno")]
        public TextMeshProUGUI textoTurno; // Arraste seu texto de turno aqui

        [Header("Configurações de Fim de Jogo")]
        public GameObject painelFimDeJogo; // Arraste o Painel/Pop-up de Game Over aqui
        public TextMeshProUGUI textoResultado; // Arraste o texto que diz quem ganhou aqui

        void Start()
        {
            // Garante que a tela de Game Over comece escondida ao iniciar o jogo
            if (painelFimDeJogo != null)
            {
                painelFimDeJogo.SetActive(false);
            }

            // Se inscreve nos eventos do tabuleiro para atualizar a tela automaticamente
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.OnTurnoAlterado += AtualizarTextoTurno;
                GeradorDeTabuleiro.Instance.OnGameOver += MostrarTelaDeVitoria;

                // AJUSTE INICIAL: Sorteia a força do primeiro turno assim que o jogo começa
                // Somente o servidor pode modificar NetworkVariables; clientes apenas leem
                if (NetworkManager.Singleton != null && NetworkManager.Singleton.IsServer)
                {
                    GeradorDeTabuleiro.Instance.forcaDoTurnoAtual.Value = Random.Range(1, 5);
                    // Força a UI a mostrar os dados certos do Jogador 1 logo no início
                    AtualizarTextoTurno(GeradorDeTabuleiro.Instance.turnoAtual.Value);
                }
                else if (NetworkManager.Singleton == null)
                {
                    // Se não houver NetworkManager (execução local), comporta-se como antes
                    GeradorDeTabuleiro.Instance.forcaDoTurnoAtual.Value = Random.Range(1, 5);
                    AtualizarTextoTurno(GeradorDeTabuleiro.Instance.turnoAtual.Value);
                }
            }
        }

        void OnDestroy()
        {
            // Limpa as inscrições de eventos para evitar erros de memória
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.OnTurnoAlterado -= AtualizarTextoTurno;
                GeradorDeTabuleiro.Instance.OnGameOver -= MostrarTelaDeVitoria;
            }
        }

        // --- MODIFICAÇÃO AQUI: Mostra o turno E a força sorteada ---
        private void AtualizarTextoTurno(int turno)
        {
            if (textoTurno != null && GeradorDeTabuleiro.Instance != null)
            {
                int forca = GeradorDeTabuleiro.Instance.forcaDoTurnoAtual.Value;

                // \n pula para a linha de baixo para o texto não ficar gigante pro lado
                textoTurno.text = $"Vez do Jogador {turno}\nForça do Golpe: {forca}";
            }
        }

        /// <summary>
        /// Ativa a tela de fim de jogo e anuncia o grande vencedor!
        /// </summary>
        private void MostrarTelaDeVitoria(int jogadorVencedor)
        {
            if (painelFimDeJogo != null)
            {
                painelFimDeJogo.SetActive(true); // Acende a tela com o botão de reiniciar
            }

            if (textoResultado != null)
            {
                textoResultado.text = $"       O Pinguim caiu!\n JOGADOR {jogadorVencedor} VENCEU! ";
            }
        }

        /// <summary>
        /// FUNÇÃO PÚBLICA DO BOTÃO: Recarrega a partida do zero.
        /// Ela vai aparecer no seu menu 'No Function' agora por causa do 'public void'.
        /// </summary>
        public void ReiniciarPartida()
        {
            Debug.Log("[UI] O botão foi clicado! Reiniciando o tabuleiro...");

            // Certifique-se de que o nome da sua cena na Unity seja exatamente "QuebraGelo"
            SceneManager.LoadScene("QuebraGelo");
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.InputSystem;

namespace JogosEmRede
{
    // Detecta cliques do jogador sobre blocos de gelo usando o novo Input System
    // e possui uma trava de segurança para evitar cliques duplos/fantasmas em blocos destruídos.
    public class ControleDeClique : MonoBehaviour
    {
        [Header("Segurança")]
        [SerializeField] private float tempoDeEsperaEntreCliques = 0.3f; // 300 milissegundos de trava
        private float proximoCliquePermitido = 0f;

        void Update()
        {
            // TRAVA DE SEGURANÇA: Se o jogo estiver processando muito rápido, ignora o clique
            if (Time.time < proximoCliquePermitido)
                return;

            // 1) Detecta clique com o botão esquerdo usando o novo Input System
            if (Mouse.current == null)
                return; // sem dispositivo de mouse disponível

            if (!Mouse.current.leftButton.wasPressedThisFrame)
                return; // nenhum clique detectado neste frame

            // Opcional: evita clicar por cima de UI (se houver)
            if (EventSystem.current != null && EventSystem.current.IsPointerOverGameObject())
                return;

            // 2) Converte posição do mouse (tela) para o mundo 2D
            if (Camera.main == null)
            {
                Debug.LogWarning("Nenhuma Camera.main encontrada para converter ScreenToWorldPoint.");
                return;
            }

            Vector2 screenPos = Mouse.current.position.ReadValue();
            Vector3 mouseWorld3 = Camera.main.ScreenToWorldPoint(new Vector3(screenPos.x, screenPos.y, Camera.main.nearClipPlane));
            Vector2 mouseWorld2 = new Vector2(mouseWorld3.x, mouseWorld3.y);

            // 3) Dispara um Raycast 2D na posição do mouse.
            RaycastHit2D hit = Physics2D.Raycast(mouseWorld2, Vector2.zero);

            // Fallback: se Raycast não encontrou nada, tente OverlapPoint
            Collider2D hitCollider = hit.collider != null ? hit.collider : Physics2D.OverlapPoint(mouseWorld2);

            if (hitCollider == null)
                return; // nada clicado

            // 4) Verifica se o objeto clicado tem BlocoDeGelo
            BlocoDeGelo bloco = hitCollider.GetComponent<BlocoDeGelo>();
            if (bloco == null)
                return; // o objeto não é um bloco de gelo

            // Se o bloco estiver protegido (centro), ignore
            if (bloco.protegido)
            {
                Debug.Log("Bloco protegido (centro) foi clicado, ignorando.");
                return;
            }

            // --- ATIVA A TRAVA DE TEMPO ---
            // Diz para o script ignorar qualquer clique nos próximos 0.3 segundos
            proximoCliquePermitido = Time.time + tempoDeEsperaEntreCliques;

            // 5) BUSCA A FORÇA SORTEADA DO TURNO ATUAL
            int forcaAplicada = 1;
            if (GeradorDeTabuleiro.Instance != null)
            {
                forcaAplicada = GeradorDeTabuleiro.Instance.forcaDoTurnoAtual;
            }

            // 6) ALTERNA O TURNO PRIMEIRO
            if (GeradorDeTabuleiro.Instance != null)
            {
                GeradorDeTabuleiro.Instance.AlternarTurno();
            }
            else
            {
                Debug.LogWarning("GeradorDeTabuleiro.Instance é nulo ao tentar alternar turno.");
            }

            // 7) APLICA O DANO NO BLOCO POR ÚLTIMO
            bloco.ReceberDano(forcaAplicada);
        }
    }
}

